arguments.command:
export OPAMROOT=/root/.opam; eval $(opam env --switch=compcert)
ls -la /tmp/CompCert/ccomp
/tmp/CompCert/ccomp -v 2>&1 | head -3
cat > /tmp/hello.c <<'EOF'
#include <stdio.h>
int fib(int n){ return n<2 ? n : fib(n-1)+fib(n-2); }
int main(void){ printf("hello compcert fib(10)=%d\n", fib(10)); return 0; }
EOF
cd /tmp && /tmp/CompCert/ccomp -o /tmp/hello /tmp/hello.c 2>&1; echo "CC_EXIT=$?"
/tmp/hello; echo "RUN_EXIT=$?"

